    async runAgentScript(agent, task, context) {
        return new Promise((resolve, reject) => {
            const args = [agent.script, 'execute', task.description];
            
            if (Object.keys(context).length > 0) {
                args.push('--context', JSON.stringify(context));
            }
            
            const process = spawn('node', args, {
                cwd: process.cwd(),
                stdio: ['pipe', 'pipe', 'pipe'],
                detached: false
            });
            
            let output = '';
            let errorOutput = '';
            
            process.stdout.on('data', (data) => {
                output += data.toString();
            });
            
            process.stderr.on('data', (data) => {
                errorOutput += data.toString();
            });
            
            process.on('error', (error) => {
                console.error(`    ❌ ${agent.name} Process error: ${error.message}`);
                reject(error);
            });
            
            process.on('exit', (code) => {
                if (code === 0) {
                    try {
                        const result = this.parseAgentOutput(output);
                        resolve(result);
                    } catch (parseError) {
                        resolve({ output, success: true });
                    }
                } else {
                    reject(new Error(`Agent process exited with code ${code}: ${errorOutput}`));
                }
            });
            
            // Timeout after 30 seconds
            setTimeout(() => {
                if (!process.killed) {
                    process.kill('SIGTERM');
                    reject(new Error('Agent execution timeout'));
                }
            }, 30000);
        });
    }

    parseAgentOutput(output) {
        try {
            // Try to parse JSON output
            const lines = output.trim().split('\n');
            const lastLine = lines[lines.length - 1];
            
            if (lastLine.startsWith('{') && lastLine.endsWith('}')) {
                return JSON.parse(lastLine);
            }
            
            // Return structured output
            return {
                output: output.trim(),
                success: true,
                timestamp: new Date().toISOString()
            };
            
        } catch (error) {
            return {
                output: output.trim(),
                success: true,
                timestamp: new Date().toISOString()
            };
        }
    }

    aggregateResults(results) {
        const aggregated = {
            successful: 0,
            failed: 0,
            results: [],
            summary: {}
        };
        
        results.forEach((result, index) => {
            if (result.status === 'fulfilled') {
                aggregated.successful++;
                aggregated.results.push(result.value);
            } else {
                aggregated.failed++;
                aggregated.results.push({
                    error: result.reason.message,
                    success: false
                });
            }
        });
        
        aggregated.summary = {
            total: results.length,
            successRate: (aggregated.successful / results.length) * 100,
            completedAt: new Date().toISOString()
        };
        
        return aggregated;
    }

